  background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
  color: #ffffff;
}

.button-primary:hover:not(:disabled) {
  opacity: 0.9;
}

.button-primary:disabled {
  opacity: 0.6;
  cursor: not-allowed;
}

